// IamServer is the server API for Iam service.
// All implementations must embed UnimplementedIamServer
// for forward compatibility.
type IamServer interface {
	// 权限校验（GetUserProfile 等见 pkg/iamcallback.IamCallback，同一进程内另注册）
	CheckPermission(context.Context, *CheckPermissionRequest) (*CheckPermissionResponse, error)
	// Gateway 基础设施
	CheckApiEnabled(context.Context, *CheckApiEnabledRequest) (*CheckApiEnabledResponse, error)
	SyncApiRoutes(context.Context, *SyncApiRoutesRequest) (*Empty, error)
	BatchRecordOperationLog(context.Context, *BatchRecordOperationLogRequest) (*Empty, error)
	RecordPerformanceLog(context.Context, *RecordPerformanceLogRequest) (*Empty, error)
	FileRegister(context.Context, *FileRegisterRequest) (*FileRegisterResponse, error)
	FileGetMeta(context.Context, *FileGetMetaRequest) (*FileGetMetaResponse, error)
	Ping(context.Context, *Empty) (*PingResponse, error)
	// Auth
	Login(context.Context, *LoginRequest) (*TokenPair, error)
	LoginFeishu(context.Context, *LoginFeishuRequest) (*TokenPair, error)
	Refresh(context.Context, *RefreshRequest) (*TokenPair, error)
	Logout(context.Context, *LogoutRequest) (*Empty, error)
	Profile(context.Context, *ProfileRequest) (*ProfileResponse, error)
	ProfileUpdate(context.Context, *ProfileUpdateRequest) (*Empty, error)
	PasswordChange(context.Context, *PasswordChangeRequest) (*Empty, error)
	// User / Role / Permission / Menu / Department / Api
	UserCreate(context.Context, *UserCreateRequest) (*Empty, error)
	UserUpdate(context.Context, *UserUpdateRequest) (*Empty, error)
	UserDelete(context.Context, *UserDeleteRequest) (*Empty, error)
	UserList(context.Context, *UserListRequest) (*UserListResponse, error)
	RoleCreate(context.Context, *RoleCreateRequest) (*Empty, error)
	RoleUpdate(context.Context, *RoleUpdateRequest) (*Empty, error)
	RoleDelete(context.Context, *RoleDeleteRequest) (*Empty, error)
	RoleList(context.Context, *RoleListRequest) (*RoleListResponse, error)
	PermissionCreate(context.Context, *PermissionCreateRequest) (*Empty, error)
	PermissionUpdate(context.Context, *PermissionUpdateRequest) (*Empty, error)
	PermissionDelete(context.Context, *PermissionDeleteRequest) (*Empty, error)
	PermissionList(context.Context, *PermissionListRequest) (*PermissionListResponse, error)
	MenuCreate(context.Context, *MenuCreateRequest) (*Empty, error)
	MenuUpdate(context.Context, *MenuUpdateRequest) (*Empty, error)
	MenuDelete(context.Context, *MenuDeleteRequest) (*Empty, error)
	MenuTree(context.Context, *Empty) (*MenuTreeResponse, error)
	MenuMyTree(context.Context, *MenuMyTreeRequest) (*MenuTreeResponse, error)
	DepartmentCreate(context.Context, *DepartmentCreateRequest) (*Empty, error)
	DepartmentUpdate(context.Context, *DepartmentUpdateRequest) (*Empty, error)
	DepartmentDelete(context.Context, *DepartmentDeleteRequest) (*Empty, error)
	DepartmentTree(context.Context, *Empty) (*DepartmentTreeResponse, error)
	ApiCreate(context.Context, *ApiCreateRequest) (*Empty, error)
	ApiUpdate(context.Context, *ApiUpdateRequest) (*Empty, error)
	ApiDelete(context.Context, *ApiDeleteRequest) (*Empty, error)
	ApiList(context.Context, *ApiListRequest) (*ApiListResponse, error)
	// RBAC 关联关系
	PermissionMenuList(context.Context, *PermissionMenuListRequest) (*PermissionMenuListResponse, error)
	PermissionMenuUpdate(context.Context, *PermissionMenuUpdateRequest) (*Empty, error)
	PermissionApiList(context.Context, *PermissionApiListRequest) (*PermissionApiListResponse, error)
	PermissionApiUpdate(context.Context, *PermissionApiUpdateRequest) (*Empty, error)
	UserRoleList(context.Context, *UserRoleListRequest) (*UserRoleListResponse, error)
	UserRoleUpdate(context.Context, *UserRoleUpdateRequest) (*Empty, error)
	RolePermissionList(context.Context, *RolePermissionListRequest) (*RolePermissionListResponse, error)
	RolePermissionUpdate(context.Context, *RolePermissionUpdateRequest) (*Empty, error)
	// Config / Dict
	ConfigCreate(context.Context, *ConfigCreateRequest) (*Empty, error)
	ConfigUpdate(context.Context, *ConfigUpdateRequest) (*Empty, error)
	ConfigDelete(context.Context, *ConfigDeleteRequest) (*Empty, error)
	ConfigList(context.Context, *ConfigListRequest) (*ConfigListResponse, error)
	ConfigGet(context.Context, *ConfigGetRequest) (*ConfigGetResponse, error)
	DictTypeCreate(context.Context, *DictTypeCreateRequest) (*Empty, error)
	DictTypeUpdate(context.Context, *DictTypeUpdateRequest) (*Empty, error)
	DictTypeDelete(context.Context, *DictTypeDeleteRequest) (*Empty, error)
	DictTypeList(context.Context, *DictTypeListRequest) (*DictTypeListResponse, error)
	DictItemCreate(context.Context, *DictItemCreateRequest) (*Empty, error)
	DictItemUpdate(context.Context, *DictItemUpdateRequest) (*Empty, error)
	DictItemDelete(context.Context, *DictItemDeleteRequest) (*Empty, error)
	DictItemList(context.Context, *DictItemListRequest) (*DictItemListResponse, error)
	DictGet(context.Context, *DictGetRequest) (*DictGetResponse, error)
	DictBatchGet(context.Context, *DictBatchGetRequest) (*DictBatchGetResponse, error)
	// File
	FileCreate(context.Context, *FileCreateRequest) (*Empty, error)
	FileUpdate(context.Context, *FileUpdateRequest) (*Empty, error)
	FileDelete(context.Context, *FileDeleteRequest) (*Empty, error)
	FileList(context.Context, *FileListRequest) (*FileListResponse, error)
	// Notice / Notification
	NoticeCreate(context.Context, *NoticeCreateRequest) (*Empty, error)
	NoticeUpdate(context.Context, *NoticeUpdateRequest) (*Empty, error)
	NoticeDelete(context.Context, *NoticeDeleteRequest) (*Empty, error)
	NoticeList(context.Context, *NoticeListRequest) (*NoticeListResponse, error)
	NotificationList(context.Context, *NotificationListRequest) (*NotificationListResponse, error)
	NotificationRead(context.Context, *NotificationReadRequest) (*Empty, error)
	NotificationReadAll(context.Context, *NotificationReadAllRequest) (*Empty, error)
	NotificationClearRead(context.Context, *NotificationClearReadRequest) (*Empty, error)
	NotificationDelete(context.Context, *NotificationDeleteRequest) (*Empty, error)
	// OperationLog / LoginLog / PerformanceLog / AuditLog（列表/详情/统计；导出见
	// services/task 的 GenericExportExecutor，走 pkg/taskcallback，不在本服务）
	OperationLogList(context.Context, *OperationLogListRequest) (*OperationLogListResponse, error)
	OperationLogDetail(context.Context, *OperationLogDetailRequest) (*OperationLogItem, error)
	LoginLogList(context.Context, *LoginLogListRequest) (*LoginLogListResponse, error)
	LoginLogDetail(context.Context, *LoginLogDetailRequest) (*LoginLogItem, error)
	LoginLogStats(context.Context, *Empty) (*LoginLogStatsResponse, error)
	PerformanceLogList(context.Context, *PerformanceLogListRequest) (*PerformanceLogListResponse, error)
	AuditLogList(context.Context, *AuditLogListRequest) (*AuditLogListResponse, error)
	AuditLogDetail(context.Context, *AuditLogDetailRequest) (*AuditLogItem, error)
	// Metric / Monitor
	MetricReport(context.Context, *MetricReportRequest) (*Empty, error)
	MetricStats(context.Context, *MetricStatsRequest) (*MetricStatsResponse, error)
	MonitorStats(context.Context, *Empty) (*MonitorStatsResponse, error)
	MonitorStatus(context.Context, *Empty) (*MonitorStatusResponse, error)
	// Demo / DailyShortSentence
	DemoCreate(context.Context, *DemoCreateRequest) (*Empty, error)
	DemoUpdate(context.Context, *DemoUpdateRequest) (*Empty, error)
	DemoDelete(context.Context, *DemoDeleteRequest) (*Empty, error)
	DemoList(context.Context, *DemoListRequest) (*DemoListResponse, error)
	DailyShortSentenceCreate(context.Context, *DailyShortSentenceCreateRequest) (*Empty, error)
	DailyShortSentenceUpdate(context.Context, *DailyShortSentenceUpdateRequest) (*Empty, error)
	DailyShortSentenceDelete(context.Context, *DailyShortSentenceDeleteRequest) (*Empty, error)
	DailyShortSentenceList(context.Context, *DailyShortSentenceListRequest) (*DailyShortSentenceListResponse, error)
	mustEmbedUnimplementedIamServer()
}

